from hashlib import sha256


def _repo_relative_identity(path):
    normalized = path.replace("\\", "/").strip("/")
    marker = "/repo/"
    if marker in f"/{normalized}":
        normalized = f"/{normalized}".split(marker, 1)[1]
    parts = [part for part in normalized.split("/") if part and part not in {".", ".."}]
    if len(parts) >= 2:
        return "/".join(parts[-2:])
    return parts[-1] if parts else "unknown"


def cache_key(user_id, path):
    identity = _repo_relative_identity(path)
    digest = sha256(f"{user_id}:{identity}".encode("utf-8")).hexdigest()[:12]
    return f"cache:{digest}"

